package com.radiacode.shared.presentation.deviceselect

import com.radiacode.shared.core.device.bluetooth.BluetoothMonitor
import com.radiacode.shared.core.device.bluetooth.BluetoothStatus
import com.radiacode.shared.core.device.model.bluetooth.RadiaCodeDiscovery
import com.radiacode.shared.core.device.scan.DeviceScanner
import com.radiacode.shared.core.device.scan.KableDeviceScanner
import com.rickclephas.kmp.observableviewmodel.MutableStateFlow
import com.rickclephas.kmp.observableviewmodel.ViewModel
import com.rickclephas.kmp.observableviewmodel.launch
import kotlinx.coroutines.CancellationException
import kotlinx.coroutines.FlowPreview
import kotlinx.coroutines.Job
import kotlinx.coroutines.channels.Channel
import kotlinx.coroutines.delay
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.collectLatest
import kotlinx.coroutines.flow.distinctUntilChanged
import kotlinx.coroutines.flow.filter
import kotlinx.coroutines.flow.map
import kotlinx.coroutines.flow.receiveAsFlow
import kotlinx.coroutines.flow.runningFold
import kotlinx.coroutines.flow.sample

private const val NOT_FOUND_TIMEOUT_MS = 30_000L
private const val SCAN_UPDATE_INTERVAL_MS = 500L

/**
 * Общая ViewModel экрана выбора устройства.
 *
 * Выводит [DeviceSelectState] (viewType + devices) из состояния Bluetooth ([BluetoothMonitor])
 * и [DeviceScanner]:
 *  - выключен      → [DeviceSelectViewType.BluetoothDisabled];
 *  - нет доступа   → [DeviceSelectViewType.BluetoothNotAuthorized];
 *  - включён       → [DeviceSelectViewType.DeviceList]; сканирует, новые устройства добавляет в конец,
 *    уже найденные обновляет на месте;
 *  - включён, но за [NOT_FOUND_TIMEOUT_MS] ничего не найдено → [DeviceSelectViewType.NoDevices].
 *
 * Питание и доступ к Bluetooth полностью инкапсулированы в [BluetoothMonitor].
 * [currentDeviceIdentifier] (уже подключённый прибор) исключается из результатов скана и подавляет
 * экран «не найдено» — его «Connected»-карточку экран показывает отдельно. Идентификатор придёт
 * из `DeviceSession.activeDevice` с фичей подключения; сейчас всегда `null`.
 */
class DeviceSelectViewModel(
    private val bluetoothMonitor: BluetoothMonitor = BluetoothMonitor(),
    private val scanner: DeviceScanner = KableDeviceScanner(),
    private val currentDeviceIdentifier: String? = null,
) : ViewModel() {

    private val _state = MutableStateFlow(viewModelScope, DeviceSelectState())
    val state = _state.asStateFlow()

    private val _effect = Channel<DeviceSelectEffect>(Channel.BUFFERED)
    val effect: Flow<DeviceSelectEffect> = _effect.receiveAsFlow()

    private var notFoundJob: Job? = null

    init {
        observe()
    }

    private fun targetViewType(status: BluetoothStatus): DeviceSelectViewType =
        when (status) {
            BluetoothStatus.PoweredOff -> DeviceSelectViewType.BluetoothDisabled
            BluetoothStatus.NotAuthorized -> DeviceSelectViewType.BluetoothNotAuthorized
            BluetoothStatus.PoweredOn, BluetoothStatus.Unknown -> DeviceSelectViewType.DeviceList
        }

    private fun observe() {
        viewModelScope.launch {
            bluetoothMonitor.status
                .map(::targetViewType)
                .distinctUntilChanged()
                .collectLatest { viewType ->
                    notFoundJob?.cancel()
                    when (viewType) {
                        DeviceSelectViewType.DeviceList -> scan()
                        else -> _state.value = DeviceSelectState(viewType = viewType)
                    }
                }
        }
    }

    @OptIn(FlowPreview::class) // sample() — для троттлинга публикаций списка
    private suspend fun scan() {
        _state.value = DeviceSelectState(viewType = DeviceSelectViewType.DeviceList)
        scheduleNotFoundCheck()
        try {
            scanner.scan()
                .filter { it.device.identifier != currentDeviceIdentifier } // подключённый прибор — отдельной карточкой, не в списке
                .runningFold(emptyMap<String, RadiaCodeDiscovery>()) { devices, discovery ->
                    devices + (discovery.device.identifier to discovery)
                }
                .sample(SCAN_UPDATE_INTERVAL_MS) // публикуем список не чаще раза в 0.5 с
                .collect { devices ->
                    _state.value = _state.value.copy(
                        viewType = DeviceSelectViewType.DeviceList,
                        devices = devices.values.toList(),
                    )
                }
        } catch (cancellation: CancellationException) {
            throw cancellation // пробрасываем отмену (сменился Bluetooth/разрешение или ViewModel очищена)
        } catch (error: Throwable) {
            notFoundJob?.cancel()
            _state.value = _state.value.copy(viewType = DeviceSelectViewType.NoDevices)
        }
    }

    /**
     * Если за [NOT_FOUND_TIMEOUT_MS] ничего не нашли — показываем экран «не найдено».
     * При уже подключённом приборе ([currentDeviceIdentifier]) экран неприменим — его карточку
     * показывает экран отдельно.
     */
    private fun scheduleNotFoundCheck() {
        notFoundJob?.cancel()
        if (currentDeviceIdentifier != null) return
        notFoundJob = viewModelScope.launch {
            delay(NOT_FOUND_TIMEOUT_MS)
            if (_state.value.devices.isEmpty()) {
                _state.value = _state.value.copy(viewType = DeviceSelectViewType.NoDevices)
            }
        }
    }

    /** «Повторить» на экране «не найдено»: вернуться к списку и перезапустить таймер. */
    fun onRetry() {
        _state.value = _state.value.copy(viewType = DeviceSelectViewType.DeviceList)
        scheduleNotFoundCheck()
    }

    // TODO: возможно, проработать usecase для этой вьюмодели
    fun onDeviceClick(peripheralId: String) {
        _effect.trySend(DeviceSelectEffect.OpenDevice(peripheralId))
    }

    // TODO: возможно, проработать usecase и отдельное решение в iOS для этой вьюмодели
    fun onCloseClick() {
        _effect.trySend(DeviceSelectEffect.NavigateBack)
    }

    fun onEnableBluetoothClick() {
        _effect.trySend(DeviceSelectEffect.RequestEnableBluetooth)
    }

    fun onGrantPermissionClick() {
        _effect.trySend(DeviceSelectEffect.RequestBluetoothPermission)
    }
}

package com.radiacode.android.presentation.deviceselect

import android.Manifest
import android.bluetooth.BluetoothAdapter
import android.content.Intent
import android.content.pm.PackageManager
import android.os.Build
import androidx.activity.compose.rememberLauncherForActivityResult
import androidx.activity.result.contract.ActivityResultContracts
import androidx.compose.runtime.Composable
import androidx.compose.runtime.getValue
import androidx.compose.ui.platform.LocalContext
import androidx.core.content.ContextCompat
import androidx.lifecycle.compose.collectAsStateWithLifecycle
import androidx.lifecycle.viewmodel.compose.viewModel
import com.radiacode.android.ui.util.CollectEffect
import com.radiacode.shared.presentation.deviceselect.DeviceSelectEffect
import com.radiacode.shared.presentation.deviceselect.DeviceSelectViewModel

/** Полный набор разрешений для запроса: scan + connect на API 31+, иначе fine location. */
private fun bluetoothPermissionsToRequest(): Array<String> =
    if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.S) {
        arrayOf(Manifest.permission.BLUETOOTH_SCAN, Manifest.permission.BLUETOOTH_CONNECT)
    } else {
        arrayOf(Manifest.permission.ACCESS_FINE_LOCATION)
    }

/**
 * Android-точка входа экрана выбора устройства: владеет общей [DeviceSelectViewModel] и превращает
 * её эффекты в системные запросы платформы (включить Bluetooth / запросить доступ). Питание и доступ
 * к Bluetooth инкапсулированы в `BluetoothMonitor`, который сам пересчитывает статус при возврате
 * приложения на передний план.
 */
@Composable
fun DeviceSelectRoute(
    onClose: () -> Unit,
) {
    val context = LocalContext.current
    val viewModel: DeviceSelectViewModel = viewModel { DeviceSelectViewModel() }
    val state by viewModel.state.collectAsStateWithLifecycle()

    val enableBluetoothLauncher = rememberLauncherForActivityResult(
        ActivityResultContracts.StartActivityForResult(),
    ) { /* Монитор Bluetooth сам сообщит новое состояние адаптера. */ }

    // На Android 12+ для ACTION_REQUEST_ENABLE нужен BLUETOOTH_CONNECT — сначала запрашиваем его, если его нет.
    val connectPermissionLauncher = rememberLauncherForActivityResult(
        ActivityResultContracts.RequestPermission(),
    ) { granted ->
        if (granted) enableBluetoothLauncher.launch(Intent(BluetoothAdapter.ACTION_REQUEST_ENABLE))
    }

    val scanPermissionLauncher = rememberLauncherForActivityResult(
        ActivityResultContracts.RequestMultiplePermissions(),
    ) { }

    fun requestEnableBluetooth() {
        val needsConnect = Build.VERSION.SDK_INT >= Build.VERSION_CODES.S &&
            ContextCompat.checkSelfPermission(context, Manifest.permission.BLUETOOTH_CONNECT) !=
            PackageManager.PERMISSION_GRANTED
        if (needsConnect) {
            connectPermissionLauncher.launch(Manifest.permission.BLUETOOTH_CONNECT)
        } else {
            enableBluetoothLauncher.launch(Intent(BluetoothAdapter.ACTION_REQUEST_ENABLE))
        }
    }

    CollectEffect(viewModel.effect) { effect ->
        when (effect) {
            DeviceSelectEffect.NavigateBack -> onClose()
            DeviceSelectEffect.RequestEnableBluetooth -> requestEnableBluetooth()
            DeviceSelectEffect.RequestBluetoothPermission ->
                scanPermissionLauncher.launch(bluetoothPermissionsToRequest())
            is DeviceSelectEffect.OpenDevice -> Unit // TODO: подключить/открыть выбранное устройство
        }
    }

    DeviceSelectScreen(
        state = state,
        onClose = viewModel::onCloseClick,
        onDeviceClick = viewModel::onDeviceClick,
        onEnableBluetooth = viewModel::onEnableBluetoothClick,
        onGrantPermission = viewModel::onGrantPermissionClick,
        onRetry = viewModel::onRetry,
    )
}

