package com.radiacode.shared.core.device.bluetooth

import android.Manifest
import android.bluetooth.BluetoothAdapter
import android.bluetooth.BluetoothManager
import android.content.BroadcastReceiver
import android.content.Context
import android.content.Intent
import android.content.IntentFilter
import android.content.pm.PackageManager
import android.os.Build
import androidx.lifecycle.Lifecycle
import androidx.lifecycle.LifecycleEventObserver
import androidx.lifecycle.ProcessLifecycleOwner
import kotlinx.coroutines.channels.awaitClose
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.callbackFlow
import kotlinx.coroutines.flow.distinctUntilChanged

/**
 * [BluetoothMonitor] для Android: совмещает питание адаптера ([BluetoothAdapter]) и runtime-разрешение
 * на сканирование, отдавая полный [BluetoothStatus], включая [BluetoothStatus.NotAuthorized].
 * Изменения питания приходят из broadcast, а разрешение пересчитывается при возврате приложения
 * на передний план ([ProcessLifecycleOwner]) — отдельного системного события на выдачу
 * runtime-разрешения нет.
 */
internal class AndroidBluetoothMonitor(
    private val context: Context,
) : BluetoothMonitor {

    override val status: Flow<BluetoothStatus> = callbackFlow {
        trySend(currentStatus())

        val receiver = object : BroadcastReceiver() {
            override fun onReceive(context: Context?, intent: Intent?) {
                if (intent?.action == BluetoothAdapter.ACTION_STATE_CHANGED) {
                    trySend(currentStatus())
                }
            }
        }
        val filter = IntentFilter(BluetoothAdapter.ACTION_STATE_CHANGED)
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            context.registerReceiver(receiver, filter, Context.RECEIVER_NOT_EXPORTED)
        } else {
            @Suppress("UnspecifiedRegisterReceiverFlag")
            context.registerReceiver(receiver, filter)
        }

        // Возврат приложения на передний план (из настроек или после системного запроса разрешения) —
        // повод перепроверить runtime-разрешение: системного broadcast на его выдачу нет.
        val lifecycleObserver = LifecycleEventObserver { _, event ->
            if (event == Lifecycle.Event.ON_RESUME) {
                trySend(currentStatus())
            }
        }
        val appLifecycle = ProcessLifecycleOwner.get().lifecycle
        appLifecycle.addObserver(lifecycleObserver)

        awaitClose {
            context.unregisterReceiver(receiver)
            appLifecycle.removeObserver(lifecycleObserver)
        }
    }.distinctUntilChanged()

    private fun currentStatus(): BluetoothStatus {
        val adapter = (context.getSystemService(Context.BLUETOOTH_SERVICE) as? BluetoothManager)?.adapter
            ?: return BluetoothStatus.Unknown
        return when {
            !adapter.isEnabled -> BluetoothStatus.PoweredOff
            !hasScanPermission() -> BluetoothStatus.NotAuthorized
            else -> BluetoothStatus.PoweredOn
        }
    }

    private fun hasScanPermission(): Boolean {
        val permission = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.S) {
            Manifest.permission.BLUETOOTH_SCAN
        } else {
            Manifest.permission.ACCESS_FINE_LOCATION
        }
        return context.checkSelfPermission(permission) == PackageManager.PERMISSION_GRANTED
    }
}

package com.radiacode.shared.presentation.deviceselect

/**
 * Одноразовые команды экрану: выполняются один раз и не входят в [DeviceSelectState].
 */
sealed interface DeviceSelectEffect {
    /** Закрыть экран выбора устройства. */
    data object NavigateBack : DeviceSelectEffect

    /** Попросить платформу показать системный запрос на включение Bluetooth. */
    data object RequestEnableBluetooth : DeviceSelectEffect

    /** Попросить платформу запросить разрешение на сканирование по Bluetooth. */
    data object RequestBluetoothPermission : DeviceSelectEffect

    /** Открыть/подключить устройство по его BLE peripheral id. */
    data class OpenDevice(val peripheralId: String) : DeviceSelectEffect
}

