import com.radiacode.shared.presentation.deviceselect.DeviceSelectState
import com.radiacode.shared.presentation.deviceselect.DeviceSelectViewType

@Composable
fun DeviceSelectScreen(
    state: DeviceSelectState,
    onClose: () -> Unit = {},
    onDeviceClick: (String) -> Unit = {},
    onEnableBluetooth: () -> Unit = {},
    onGrantPermission: () -> Unit = {},
    onRetry: () -> Unit = {},
    modifier: Modifier = Modifier,
) {
    val density = LocalDensity.current
    val statusBarTop = WindowInsets.statusBars.asPaddingValues().calculateTopPadding()
    val navigationBarBottom = WindowInsets.navigationBars.asPaddingValues().calculateBottomPadding()
    val listState = rememberLazyListState()
    val collapseRangePx = with(density) {
        DeviceSelectHeaderDimensions.headerScrollRange.toPx()
    }
    val collapseFraction by remember(listState, collapseRangePx) {
        derivedStateOf {
            val scrollOffset = if (listState.firstVisibleItemIndex > 0) {
                collapseRangePx
            } else {
                listState.firstVisibleItemScrollOffset.toFloat()
            }

            (scrollOffset / collapseRangePx).coerceIn(0f, 1f)
        }
    }

    // Эффект, нужный для того, чтобы хедер не "завис" в промежуточном положении.
    // У него либо два стейта - обычный раскрытый, либо свернутый при скролле
    LaunchedEffect(listState, collapseRangePx) {
        snapshotFlow { listState.isScrollInProgress }.collect { scrolling ->
            if (!scrolling && listState.firstVisibleItemIndex == 0) {
                val offset = listState.firstVisibleItemScrollOffset.toFloat()
                if (offset > 0f && offset < collapseRangePx) {
                    val target = if (offset >= collapseRangePx / 2f) collapseRangePx else 0f
                    listState.animateScrollBy(target - offset)
                }
            }
        }
    }

    Surface(
        modifier = modifier.fillMaxSize(),
        color = MaterialTheme.colorScheme.background,
    ) {
        Box(Modifier.fillMaxSize()) {
            DeviceSelectExpandedHeader(
                collapseFraction = collapseFraction,
                statusBarTop = statusBarTop,
            )

            when (state.viewType) {
                DeviceSelectViewType.DeviceList -> DeviceList(
                    state = state,
                    listState = listState,
                    statusBarTop = statusBarTop,
                    navigationBarBottom = navigationBarBottom,
                    onDeviceClick = onDeviceClick,
                )

                DeviceSelectViewType.NoDevices -> DeviceSelectStatus(
                    iconRes = R.drawable.ic_manage_search_24px,
                    titleRes = R.string.devicelist_notfound_title,
                    subtitleRes = R.string.devicelist_notfound_subtitle,
                    actionLabelRes = R.string.devicelist_try_again,
                    onAction = onRetry,
                )

                DeviceSelectViewType.BluetoothDisabled -> DeviceSelectStatus(
                    iconRes = R.drawable.ic_bluetooth_disabled_24px,
                    titleRes = R.string.devicelist_bleoff_title,
                    subtitleRes = R.string.devicelist_bleoff_subtitle,
                    actionLabelRes = R.string.devicelist_enable_bluetooth,
                    onAction = onEnableBluetooth,
                )

                DeviceSelectViewType.BluetoothNotAuthorized -> DeviceSelectStatus(
                    iconRes = R.drawable.ic_settings_bluetooth_24px,
                    titleRes = R.string.devicelist_bleperm_title,
                    subtitleRes = R.string.device_bleperm_subtitle,
                    actionLabelRes = R.string.devicelist_grant_permission,
                    onAction = onGrantPermission,
                )
            }

            DeviceSelectTopBar(
                collapseFraction = collapseFraction,
                statusBarTop = statusBarTop,
                onClose = onClose,
            )
        }
    }
}

@Composable
private fun DeviceList(
    state: DeviceSelectState,
    listState: LazyListState,
    statusBarTop: Dp,
    navigationBarBottom: Dp,
    onDeviceClick: (String) -> Unit,
) {
    LazyColumn(
        state = listState,
        contentPadding = PaddingValues(
            start = 16.dp,
            top = statusBarTop + DeviceSelectHeaderDimensions.collapsedListTop,
            end = 16.dp,
            bottom = navigationBarBottom + 32.dp,
        ),
        verticalArrangement = Arrangement.spacedBy(12.dp),
    ) {
        item(key = "header-spacer") {
            Spacer(Modifier.height(DeviceSelectHeaderDimensions.headerScrollRange))
        }

        items(
            items = state.devices,
            key = { discovery -> discovery.device.identifier },
        ) { discovery ->
            DeviceSelectCard(
                name = discovery.device.model.displayName,
                serial = discovery.device.identifier,
                signal = discovery.signal,
                modifier = Modifier.clickable { onDeviceClick(discovery.peripheralId) },
            )
        }

        item(key = "searching") {
            SearchingRow()
        }
    }
}

@Composable
private fun SearchingRow(modifier: Modifier = Modifier) {
    Row(
        modifier = modifier
            .fillMaxWidth()
            .padding(vertical = 20.dp),
        horizontalArrangement = Arrangement.Center,
        verticalAlignment = Alignment.CenterVertically,
    ) {
        Spinner(Modifier.size(24.dp))

        Spacer(Modifier.width(12.dp))

        Text(
            text = stringResource(R.string.devicelist_searching),
            style = MaterialTheme.typography.bodyLarge,
        )
    }
}

