package com.radiacode.android.presentation.deviceselect

import android.Manifest
import android.bluetooth.BluetoothAdapter
import android.content.Intent
import android.content.pm.PackageManager
import android.os.Build
import androidx.activity.compose.rememberLauncherForActivityResult
import androidx.activity.result.contract.ActivityResultContracts
import androidx.compose.runtime.Composable
import androidx.compose.runtime.getValue
import androidx.compose.ui.platform.LocalContext
import androidx.core.content.ContextCompat
import androidx.lifecycle.compose.collectAsStateWithLifecycle
import androidx.lifecycle.viewmodel.compose.viewModel
import com.radiacode.android.ui.util.CollectEffect
import com.radiacode.shared.presentation.deviceselect.DeviceSelectEffect
import com.radiacode.shared.presentation.deviceselect.DeviceSelectViewModel

/** Полный набор разрешений для запроса: scan + connect на API 31+, иначе fine location. */
private fun bluetoothPermissionsToRequest(): Array<String> =
    if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.S) {
        arrayOf(Manifest.permission.BLUETOOTH_SCAN, Manifest.permission.BLUETOOTH_CONNECT)
    } else {
        arrayOf(Manifest.permission.ACCESS_FINE_LOCATION)
    }

/**
 * Android-точка входа экрана выбора устройства: владеет общей [DeviceSelectViewModel] и превращает
 * её эффекты в системные запросы платформы (включить Bluetooth / запросить доступ). Питание и доступ
 * к Bluetooth инкапсулированы в `BluetoothMonitor`, который сам пересчитывает статус при возврате
 * приложения на передний план.
 */
@Composable
fun DeviceSelectRoute(
    onClose: () -> Unit,
) {
    val context = LocalContext.current
    val viewModel: DeviceSelectViewModel = viewModel { DeviceSelectViewModel() }
    val state by viewModel.state.collectAsStateWithLifecycle()

    val enableBluetoothLauncher = rememberLauncherForActivityResult(
        ActivityResultContracts.StartActivityForResult(),
    ) { /* Монитор Bluetooth сам сообщит новое состояние адаптера. */ }

    // На Android 12+ для ACTION_REQUEST_ENABLE нужен BLUETOOTH_CONNECT — сначала запрашиваем его, если его нет.
    val connectPermissionLauncher = rememberLauncherForActivityResult(
        ActivityResultContracts.RequestPermission(),
    ) { granted ->
        if (granted) enableBluetoothLauncher.launch(Intent(BluetoothAdapter.ACTION_REQUEST_ENABLE))
    }

    val scanPermissionLauncher = rememberLauncherForActivityResult(
        ActivityResultContracts.RequestMultiplePermissions(),
    ) { }

    fun requestEnableBluetooth() {
        val needsConnect = Build.VERSION.SDK_INT >= Build.VERSION_CODES.S &&
            ContextCompat.checkSelfPermission(context, Manifest.permission.BLUETOOTH_CONNECT) !=
            PackageManager.PERMISSION_GRANTED
        if (needsConnect) {
            connectPermissionLauncher.launch(Manifest.permission.BLUETOOTH_CONNECT)
        } else {
            enableBluetoothLauncher.launch(Intent(BluetoothAdapter.ACTION_REQUEST_ENABLE))
        }
    }

    CollectEffect(viewModel.effect) { effect ->
        when (effect) {
            DeviceSelectEffect.NavigateBack -> onClose()
            DeviceSelectEffect.RequestEnableBluetooth -> requestEnableBluetooth()
            DeviceSelectEffect.RequestBluetoothPermission ->
                scanPermissionLauncher.launch(bluetoothPermissionsToRequest())
            is DeviceSelectEffect.OpenDevice -> Unit // TODO: подключить/открыть выбранное устройство
        }
    }

    DeviceSelectScreen(
        state = state,
        onClose = viewModel::onCloseClick,
        onDeviceClick = viewModel::onDeviceClick,
        onEnableBluetooth = viewModel::onEnableBluetoothClick,
        onGrantPermission = viewModel::onGrantPermissionClick,
        onRetry = viewModel::onRetry,
    )
}

