private suspend fun scan() {
    _state.value = DeviceSelectState(viewType = DeviceSelectViewType.DeviceList)
    scheduleNotFoundCheck()
    val order = mutableListOf<String>()                   // порядок карточек на экране (identifier)
    val byId = mutableMapOf<String, RadiaCodeDiscovery>() // последние данные по identifier
    try {
        scanner.scan()
            .filter { it.device.identifier != currentDeviceIdentifier } // подключённый прибор — отдельной карточкой, не в списке
            .chunkedByTime(SCAN_UPDATE_INTERVAL_MS) // копим скан окнами по 0.5 c
            .collect { window ->
                // новые приборы окна — те, которых ещё нет в списке (дедуп внутри окна)
                val fresh = window
                    .filter { it.device.identifier !in byId }
                    .associateBy { it.device.identifier }
                // обновляем данные всех увиденных (у уже показанных меняется в т.ч. сигнал)
                window.forEach { byId[it.device.identifier] = it }
                // новые — сортируем по силе сигнала и дописываем в конец, не трогая порядок показанных
                order += fresh.values
                    .sortedBy { it.signal }
                    .map { it.device.identifier }
                _state.value = _state.value.copy(
                    viewType = DeviceSelectViewType.DeviceList,
                    devices = order.mapNotNull(byId::get),
                )
            }
    } catch (cancellation: CancellationException) {
        throw cancellation // пробрасываем отмену (сменился Bluetooth/разрешение или ViewModel очищена)
    } catch (error: Throwable) {
        notFoundJob?.cancel()
        _state.value = _state.value.copy(viewType = DeviceSelectViewType.NoDevices)
    }
}

/**
 * Группирует элементы во временные окна: окно открывается приходом первого элемента, копит всё
 * за [periodMs] и отдаёт непустым списком. Пустые окна не эмитятся, остаток — при завершении потока.
 */
@OptIn(FlowPreview::class) // produceIn
private fun <T> Flow<T>.chunkedByTime(periodMs: Long): Flow<List<T>> = flow {
    coroutineScope {
        val upstream = produceIn(this)
        while (true) {
            val first = upstream.receiveCatching().getOrNull() ?: break
            val window = mutableListOf(first)
            withTimeoutOrNull(periodMs) {
                for (item in upstream) {
                    window.add(item)
                }
            }
            emit(window)
        }
    }
}

