 * на месте), новые сортируются по силе сигнала и дописываются в конец — список не «прыгает».
 */
private data class OrderedDevices(
    private val order: List<String> = emptyList(),
    private val byId: Map<String, RadiaCodeDiscovery> = emptyMap(),
) {
    fun merge(window: List<RadiaCodeDiscovery>): OrderedDevices {
        val updated = byId + window.associateBy { it.device.identifier }
        val freshIds = window
            .filterNot { it.device.identifier in byId }
            .distinctBy { it.device.identifier }
            .sortedBy { it.signal }                       // Strong → … → NoSignal (сильные выше)
            .map { it.device.identifier }
        return OrderedDevices(order + freshIds, updated)
    }

    fun toList(): List<RadiaCodeDiscovery> = order.mapNotNull(byId::get)
}
