 * Общая ViewModel экрана выбора устройства.
 *
 * Выводит [DeviceSelectState] (viewType + devices) из состояния Bluetooth ([BluetoothMonitor])
 * и [DeviceScanner]:
 *  - выключен      → [DeviceSelectViewType.BluetoothDisabled];
 *  - нет доступа   → [DeviceSelectViewType.BluetoothNotAuthorized];
 *  - включён       → [DeviceSelectViewType.DeviceList]; сканирует, новые устройства добавляет в конец,
 *    уже найденные обновляет на месте;
 *  - включён, но за [NOT_FOUND_TIMEOUT_MS] ничего не найдено → [DeviceSelectViewType.NoDevices].
 *
 * Питание и доступ к Bluetooth полностью инкапсулированы в [BluetoothMonitor].
 * [currentDeviceIdentifier] (уже подключённый прибор) исключается из результатов скана и подавляет
 * экран «не найдено» — его «Connected»-карточку экран показывает отдельно. Идентификатор придёт
 * из `DeviceSession.activeDevice` с фичей подключения; сейчас всегда `null`.
 */
class DeviceSelectViewModel(
    private val bluetoothMonitor: BluetoothMonitor = BluetoothMonitor(),
    private val scanner: DeviceScanner = KableDeviceScanner(),
    private val currentDeviceIdentifier: String? = null,
) : ViewModel() {

    private val _state = MutableStateFlow(viewModelScope, DeviceSelectState())
    val state = _state.asStateFlow()

    private val _effect = Channel<DeviceSelectEffect>(Channel.BUFFERED)
    val effect: Flow<DeviceSelectEffect> = _effect.receiveAsFlow()

    private var notFoundJob: Job? = null

    init {
        observe()
    }

    private fun targetViewType(status: BluetoothStatus): DeviceSelectViewType =
        when (status) {
            BluetoothStatus.PoweredOff -> DeviceSelectViewType.BluetoothDisabled
            BluetoothStatus.NotAuthorized -> DeviceSelectViewType.BluetoothNotAuthorized
            BluetoothStatus.PoweredOn, BluetoothStatus.Unknown -> DeviceSelectViewType.DeviceList
        }

    private fun observe() {
        viewModelScope.launch {
            bluetoothMonitor.status
                .map(::targetViewType)
                .distinctUntilChanged()
                .collectLatest { viewType ->
                    notFoundJob?.cancel()
                    when (viewType) {
                        DeviceSelectViewType.DeviceList -> scan()
                        else -> _state.value = DeviceSelectState(viewType = viewType)
                    }
                }
        }
    }

    @OptIn(FlowPreview::class) // sample() — для троттлинга публикаций списка
    private suspend fun scan() {
        _state.value = DeviceSelectState(viewType = DeviceSelectViewType.DeviceList)
        scheduleNotFoundCheck()
        try {
            scanner.scan()
                .filter { it.device.identifier != currentDeviceIdentifier } // подключённый прибор — отдельной карточкой, не в списке
                .runningFold(emptyMap<String, RadiaCodeDiscovery>()) { devices, discovery ->
                    devices + (discovery.device.identifier to discovery)
                }
                .sample(SCAN_UPDATE_INTERVAL_MS) // публикуем список не чаще раза в 0.5 с
                .collect { devices ->
                    _state.value = _state.value.copy(
                        viewType = DeviceSelectViewType.DeviceList,
                        devices = devices.values.toList(),
                    )
                }
        } catch (cancellation: CancellationException) {
            throw cancellation // пробрасываем отмену (сменился Bluetooth/разрешение или ViewModel очищена)
        } catch (error: Throwable) {
            notFoundJob?.cancel()
            _state.value = _state.value.copy(viewType = DeviceSelectViewType.NoDevices)
        }
    }

    /**
     * Если за [NOT_FOUND_TIMEOUT_MS] ничего не нашли — показываем экран «не найдено».
     * При уже подключённом приборе ([currentDeviceIdentifier]) экран неприменим — его карточку
     * показывает экран отдельно.
     */
    private fun scheduleNotFoundCheck() {
        notFoundJob?.cancel()
        if (currentDeviceIdentifier != null) return
        notFoundJob = viewModelScope.launch {
            delay(NOT_FOUND_TIMEOUT_MS)
            if (_state.value.devices.isEmpty()) {
                _state.value = _state.value.copy(viewType = DeviceSelectViewType.NoDevices)
            }
        }
    }

    /** «Повторить» на экране «не найдено»: вернуться к списку и перезапустить таймер. */
    fun onRetry() {
        _state.value = _state.value.copy(viewType = DeviceSelectViewType.DeviceList)
        scheduleNotFoundCheck()
    }

    // TODO: возможно, проработать usecase для этой вьюмодели
    fun onDeviceClick(peripheralId: String) {
        _effect.trySend(DeviceSelectEffect.OpenDevice(peripheralId))
    }
}

