private suspend fun scan() {
    _state.value = DeviceSelectState(viewType = DeviceSelectViewType.DeviceList)
    scheduleNotFoundCheck()
    val devices = linkedMapOf<String, RadiaCodeDiscovery>()
    try {
        scanner.scan()
            .onEach { notFoundJob?.cancel() } // нашли прибор — снимаем таймер «не найдено»
            .filter { it.device.identifier != currentDeviceIdentifier } // подключённый — отдельной карточкой, не в списке
            .chunkedByTime(SCAN_UPDATE_INTERVAL_MS) // копим скан окнами по 0.5 c
            .collect { window ->
                val sorted = window.sortedBy { it.signal } // новые за окно — по сигналу (Strong выше)
                for (discovery in sorted) {
                    devices[discovery.device.identifier] = discovery // существующий — на месте, новый — в конец
                }
                _state.value = _state.value.copy(
                    viewType = DeviceSelectViewType.DeviceList,
                    devices = devices.values.toList(),
                )
            }
    } catch (cancellation: CancellationException) {
        throw cancellation // пробрасываем отмену (сменился Bluetooth/разрешение или ViewModel очищена)
    } catch (error: Throwable) {
        notFoundJob?.cancel()
        _state.value = _state.value.copy(viewType = DeviceSelectViewType.NoDevices)
    }
}

