package com.radiacode.android

import androidx.compose.animation.ContentTransform
import androidx.compose.animation.EnterTransition
import androidx.compose.animation.ExitTransition
import androidx.compose.animation.slideInHorizontally
import androidx.compose.animation.slideOutHorizontally
import androidx.compose.runtime.Composable
import androidx.compose.ui.tooling.preview.Preview
import androidx.navigation3.runtime.entryProvider
import androidx.navigation3.runtime.rememberNavBackStack
import androidx.navigation3.ui.NavDisplay
import com.radiacode.android.navigation.Route
import com.radiacode.android.presentation.dashboard.DashboardScreen
import com.radiacode.android.presentation.deviceselect.DeviceSelectRoute
import com.radiacode.android.ui.theme.AppTheme

private val DeviceSelectTransitions: Map<String, Any> =
    NavDisplay.transitionSpec {
        ContentTransform(
            targetContentEnter = slideInHorizontally(initialOffsetX = { it }),
            initialContentExit = ExitTransition.None,
            targetContentZIndex = 1f,
        )
    } + NavDisplay.popTransitionSpec {
        ContentTransform(
            targetContentEnter = EnterTransition.None,
            initialContentExit = slideOutHorizontally(targetOffsetX = { it }),
            targetContentZIndex = 0f,
        )
    } + NavDisplay.predictivePopTransitionSpec {
        ContentTransform(
            targetContentEnter = EnterTransition.None,
            initialContentExit = slideOutHorizontally(targetOffsetX = { it }),
            targetContentZIndex = 0f,
        )
    }

@Composable
fun App() {
    val backStack = rememberNavBackStack(Route.Dashboard)

    NavDisplay(
        backStack = backStack,
        onBack = { backStack.removeLastOrNull() },
        entryProvider = entryProvider {
            entry<Route.Dashboard> {
                DashboardScreen(
                    onOpenDeviceSelect = { backStack.add(Route.DeviceSelect) },
                )
            }
            entry<Route.DeviceSelect>(metadata = DeviceSelectTransitions) {
                DeviceSelectRoute(onClose = { backStack.removeLastOrNull() })
            }
        },
    )
}

@Preview
@Composable
private fun AppPreview() {
    AppTheme { App() }
}

